// ─── BUTTON ──────────────────────────────────────────────────
function Btn({children,v="primary",onClick,disabled,style={},size="md",full}){
  const [h,setH]=useState(false);
  const pd=size==="lg"?"16px 36px":size==="sm"?"8px 18px":"11px 26px";
  const fs=size==="lg"?16:size==="sm"?13:14;
  const radius=size==="lg"?14:size==="sm"?9:11;
  const vars={
    primary:{background:h?"#0f1d42":C.navy,color:C.white,boxShadow:h?shadow.lg:shadow.sm,transform:h?"translateY(-2px)":"none",letterSpacing:"0.02em"},
    grad:{background:C.grad,color:C.white,boxShadow:h?shadow.indigo:shadow.sm,transform:h?"translateY(-2px)":"none",letterSpacing:"0.02em"},
    orange:{background:C.gradOrange,color:C.white,boxShadow:h?`0 8px 32px rgba(249,115,22,0.35)`:shadow.sm,transform:h?"translateY(-2px)":"none"},
    outline:{background:h?"rgba(61,79,248,0.04)":"transparent",color:C.navy,border:`1.5px solid ${h?C.indigo:C.border}`,boxShadow:h?shadow.sm:"none",transform:h?"translateY(-1px)":"none"},
    ghost:{background:h?"rgba(10,15,30,0.05)":"transparent",color:C.textMid},
    white:{background:h?"rgba(255,255,255,0.95)":C.white,color:C.navy,boxShadow:h?shadow.md:shadow.sm,transform:h?"translateY(-2px)":"none"},
    danger:{background:h?"#c81e2a":C.danger,color:C.white,transform:h?"translateY(-1px)":"none"},
    success:{background:h?"#00a073":C.success,color:C.white,transform:h?"translateY(-1px)":"none"},
    warning:{background:h?"#d99200":C.warning,color:C.white,transform:h?"translateY(-1px)":"none"},
    indigo:{background:h?"#2f3fe0":C.indigo,color:C.white,boxShadow:h?shadow.indigo:shadow.sm,transform:h?"translateY(-2px)":"none"},
    gold:{background:C.gradGold,color:C.obsidian,boxShadow:h?shadow.gold:shadow.sm,transform:h?"translateY(-2px)":"none",fontWeight:800},
  };
  return (
    <button disabled={disabled} onMouseEnter={()=>setH(true)} onMouseLeave={()=>setH(false)} onClick={onClick}
      style={{padding:pd,borderRadius:radius,border:"none",cursor:disabled?"not-allowed":"pointer",fontWeight:700,fontSize:fs,fontFamily:FONT_BODY,transition:"all 0.2s cubic-bezier(0.4,0,0.2,1)",display:"inline-flex",alignItems:"center",gap:8,opacity:disabled?0.55:1,width:full?"100%":"auto",justifyContent:full?"center":"flex-start",...vars[v],...style}}>
      {children}
    </button>
  );
}

// ─── LOGO ────────────────────────────────────────────────────
function Logo({size="nav",onClick,white=false}){
  const iconH=size==="hero"?80:size==="lg"?60:size==="md"?48:32;
  const titleSize=size==="hero"?30:size==="lg"?21:size==="md"?17:14;
  const subSize=size==="hero"?12:size==="lg"?10:9;
  const titleCol=white?"#fff":C.obsidian;
  const subCol=white?"rgba(255,255,255,0.5)":C.textLight;
  return (
    <div onClick={onClick} style={{display:"inline-flex",alignItems:"center",gap:size==="hero"?14:9,cursor:onClick?"pointer":"default"}}>
      <img src={ICON_IMG} alt="ZentriqFlow" style={{height:iconH,width:"auto"}}/>
      <div>
        <div style={{fontWeight:900,fontSize:titleSize,color:titleCol,letterSpacing:"-0.5px",lineHeight:1.1,fontFamily:FONT_DISPLAY}}>ZentriqFlow</div>
        <div style={{fontSize:subSize,color:subCol,fontWeight:600,lineHeight:1.3,letterSpacing:"0.03em",textTransform:"uppercase"}}>No booking. No stress.</div>
      </div>
    </div>
  );
}

function QRImg({url,size=160}){
  return <img src={`https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodeURIComponent(url)}`} alt="QR" style={{width:size,height:size,borderRadius:10,border:`1px solid ${C.border}`}}/>;
}

// ─── STARS ───────────────────────────────────────────────────
function Stars({rating,max=5,size=14,interactive=false,onRate}){
  const [hov,setHov]=useState(0);
  const d=hov||rating;
  return (
    <div style={{display:"flex",gap:1}}>
      {Array.from({length:max}).map((_,i)=>(
        <span key={i} onClick={interactive?()=>onRate&&onRate(i+1):undefined}
          onMouseEnter={interactive?()=>setHov(i+1):undefined}
          onMouseLeave={interactive?()=>setHov(0):undefined}
          style={{fontSize:size,cursor:interactive?"pointer":"default",color:i<d?"#f59e0b":"#d1d5db",lineHeight:1}}>★</span>
      ))}
    </div>
  );
}


// ─── NAVBAR ──────────────────────────────────────────────────
function Navbar({onNavigate,user,currentView}){
  const [menu,setMenu]=useState(false);
  const [scrolled,setScrolled]=useState(false);
  const [wide,setWide]=useState(typeof window!=="undefined"?window.innerWidth>=940:true);
  useEffect(()=>{
    const onScroll=()=>setScrolled(window.scrollY>12);
    const onResize=()=>setWide(window.innerWidth>=940);
    window.addEventListener("scroll",onScroll);
    window.addEventListener("resize",onResize);
    return ()=>{window.removeEventListener("scroll",onScroll);window.removeEventListener("resize",onResize);};
  },[]);
  const links=[
    {label:"Features",view:"home",hash:"features"},
    {label:"How it works",view:"how-it-works"},
    {label:"Find a Business",view:"find-barber"},
    {label:"Pricing",view:"pricing"},
  ];
  return (
    <nav style={{...S.nav,boxShadow:scrolled?shadow.md:"none",transition:"box-shadow 0.3s"}}>
      <div style={S.navInner}>
        <Logo size="nav" onClick={()=>onNavigate("home")}/>
        {wide&&(
          <div style={{display:"flex",alignItems:"center",gap:2,position:"absolute",left:"50%",transform:"translateX(-50%)"}}>
            {links.map(l=>(
              <button key={l.label} onClick={()=>onNavigate(l.view,l.hash)}
                style={{padding:"8px 14px",background:"none",border:"none",cursor:"pointer",fontSize:13,fontWeight:currentView===l.view?700:500,color:currentView===l.view?C.text:C.textMid,borderRadius:9,fontFamily:FONT_BODY,letterSpacing:"0.01em",transition:"all 0.15s"}}
                onMouseEnter={e=>{e.currentTarget.style.background="rgba(10,15,30,0.05)";e.currentTarget.style.color=C.text;}}
                onMouseLeave={e=>{e.currentTarget.style.background="none";e.currentTarget.style.color=currentView===l.view?C.text:C.textMid;}}>
                {l.label}
              </button>
            ))}
          </div>
        )}
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          {wide&&<button onClick={()=>onNavigate("barber-login")} style={{padding:"8px 16px",background:"none",border:"none",cursor:"pointer",fontSize:13,fontWeight:500,color:C.textMid,borderRadius:9,fontFamily:FONT_BODY,transition:"all 0.15s"}} onMouseEnter={e=>{e.currentTarget.style.background="rgba(10,15,30,0.05)";}} onMouseLeave={e=>{e.currentTarget.style.background="none";}}>Staff login</button>}
          {wide&&<button onClick={()=>onNavigate(user?"admin":"login")} style={{padding:"8px 16px",background:"none",border:"none",cursor:"pointer",fontSize:13,fontWeight:500,color:C.textMid,borderRadius:9,fontFamily:FONT_BODY,transition:"all 0.15s"}} onMouseEnter={e=>{e.currentTarget.style.background="rgba(10,15,30,0.05)";}} onMouseLeave={e=>{e.currentTarget.style.background="none";}}>{user?"Dashboard":"Log in"}</button>}
          {wide&&<Btn v="primary" onClick={()=>onNavigate(user?"admin":"signup")} size="sm" style={{borderRadius:10,letterSpacing:"0.02em"}}>Get early access</Btn>}
          <button onClick={()=>setMenu(!menu)} style={{background:"none",border:`1px solid ${C.border}`,borderRadius:10,cursor:"pointer",padding:"8px 10px",display:"flex",flexDirection:"column",gap:4,transition:"border-color 0.15s"}}
            onMouseEnter={e=>e.currentTarget.style.borderColor=C.borderStrong} onMouseLeave={e=>e.currentTarget.style.borderColor=C.border}>
            {[0,1,2].map(i=><span key={i} style={{display:"block",width:16,height:1.5,background:C.text,borderRadius:2,transition:"all 0.2s",transform:menu&&i===0?"rotate(45deg) translate(4px,4px)":menu&&i===2?"rotate(-45deg) translate(4px,-4px)":"none",opacity:menu&&i===1?0:1}}/>)}
          </button>
        </div>
      </div>
      {menu&&(
        <div style={{position:"fixed",inset:0,top:70,background:"rgba(10,15,30,0.6)",backdropFilter:"blur(8px)",zIndex:99}} onClick={()=>setMenu(false)}>
          <div style={{background:C.bgCard,padding:"1.5rem 2rem 2rem",boxShadow:shadow.xxl,borderBottom:`1px solid ${C.border}`}} onClick={e=>e.stopPropagation()}>
            {[...links,
              {label:"Staff login",view:"barber-login"},
              {label:"Log in",view:user?"admin":"login"},
            ].map(l=>(
              <button key={l.label} onClick={()=>{onNavigate(l.view,l.hash);setMenu(false);}}
                style={{display:"block",width:"100%",textAlign:"left",padding:"14px 0",background:"none",border:"none",borderBottom:`1px solid ${C.border}`,cursor:"pointer",fontSize:15,fontWeight:500,color:C.text,fontFamily:FONT_BODY}}>
                {l.label}
              </button>
            ))}
            <div style={{marginTop:"1.25rem"}}>
              <Btn v="primary" full size="lg" onClick={()=>{onNavigate(user?"admin":"signup");setMenu(false);}}>Get early access →</Btn>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
}

