                    <div style={{width:34,height:34,borderRadius:"50%",background:C.grad,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800,color:"#fff",fontSize:14,flexShrink:0}}>{b.name[0].toUpperCase()}</div>
