// ─── ROOT APP ─────────────────────────────────────────────────
export default function App(){
  const [view,setView]=useState("home");
  const [shopSlug,setShopSlug]=useState(null);
  const [entryId,setEntryId]=useState(null);
  const [user,setUser]=useState(null);

  useEffect(()=>{
    supabase.auth.getSession().then(({data})=>setUser(data?.session?.user||null));
    const {data:{subscription}}=supabase.auth.onAuthStateChange((_,session)=>setUser(session?.user||null));
    // URL routing
    const path=window.location.pathname;
    const sm=path.match(/^\/shop\/([^/]+)/);
    const om=path.match(/^\/order\/([^/]+)/);
    const stm=path.match(/^\/status\/([^/]+)/);
    const trm=path.match(/^\/track\/([^/]+)/);
    const bm=path.match(/^\/barber(\/.*)?$/);
    if(sm){setShopSlug(sm[1]);setView("join");}
    else if(om){setShopSlug(om[1]);setView("takeaway-order");}
    else if(stm){setEntryId(stm[1]);setView("status");}
    else if(trm){setEntryId(trm[1]);setView("track-order");}
    else if(bm){setView("barber-login");}
    return ()=>subscription.unsubscribe();
  },[]);

  function navigate(v,hash,slug){
    if(slug){window.location.href=`/shop/${slug}`;return;}
    setView(v);
    if(hash) setTimeout(()=>document.getElementById(hash)?.scrollIntoView({behavior:"smooth"}),100);
    window.scrollTo({top:0,behavior:"smooth"});
  }

  // URL-based views
  if(view==="join"&&shopSlug) return <CustomerJoin shopSlug={shopSlug}/>;
  if(view==="takeaway-order"&&shopSlug) return <TakeawayOrderPage shopSlug={shopSlug}/>;
  if(view==="status"&&entryId) return <CustomerStatus entryId={entryId}/>;
  if(view==="track-order"&&entryId) return <OrderTrackPage orderId={entryId}/>;
  if(view==="barber-login") return <BarberLogin onNavigate={navigate}/>;

  // Auth views
  if(view==="admin") return <AdminDashboard user={user} onLogout={()=>{supabase.auth.signOut();setView("home");setUser(null);}} onNavigate={navigate}/>;
  if(view==="login") return <LoginPage onLogin={(u)=>{setUser(u);navigate("admin");}} onNavigate={navigate}/>;
  if(view==="signup") return <SignupPage onLogin={(u)=>{setUser(u);navigate("admin");}} onNavigate={navigate}/>;

  // Page views
  if(view==="how-it-works") return <HowItWorksPage onNavigate={navigate} user={user}/>;
  if(view==="faq") return <FaqPage onNavigate={navigate} user={user}/>;
  if(view==="contact") return <ContactPage onNavigate={navigate} user={user}/>;
  if(view==="privacy") return <PrivacyPage onNavigate={navigate} user={user}/>;
  if(view==="terms") return <TermsPage onNavigate={navigate} user={user}/>;
  if(view==="pricing") return <PricingPage onNavigate={navigate} user={user}/>;
  if(view==="find-barber") return <FindBarberPage onNavigate={navigate} user={user}/>;

  return <HomePage onNavigate={navigate} user={user}/>;
}
